import React, { useState, useEffect } from 'react';
import { Plus, Search, Download, Trash2, Upload, Image as ImageIcon } from 'lucide-react';
import './App.css';
import { GoogleGenerativeAI } from '@google/generative-ai';

// LƯU Ý BẢO MẬT: Dán API Key MỚI của Thầy vào đây. Tuyệt đối không share cho ai!
const GEMINI_API_KEY = 'AIzaSyBGqPDomfO4sA5NY6OSBpxzjHqBzrV4X4g'; 
const genAI = new GoogleGenerativeAI(GEMINI_API_KEY);

function App() {
  const [problems, setProblems] = useState([]);
  const [showAddForm, setShowAddForm] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedTopic, setSelectedTopic] = useState('all');
  const [selectedLevel, setSelectedLevel] = useState('all');
  const [filteredProblems, setFilteredProblems] = useState([]);
  const [expandedId, setExpandedId] = useState(null);
  const [isImporting, setIsImporting] = useState(false);
  const [isOCRing, setIsOCRing] = useState(false);

  // STATE MỚI: Công tắc bật/tắt AI
  const [useAI, setUseAI] = useState(true); 

  const [formData, setFormData] = useState({
    rawLatex: '', 
    topic: 'Đạo hàm',
    level: 1,
    type: 'Tự luận',
    tags: '',
    notes: ''
  });

  const topics = [
    'Đạo hàm', 'Tích phân', 'Lượng giác', 'Số phức', 
    'Ma trận', 'Hình học không gian', 'Xác suất', 'Giới hạn'
  ];

  useEffect(() => {
    const saved = localStorage.getItem('problems');
    if (saved) {
      setProblems(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    let result = problems;

    if (searchTerm) {
      result = result.filter(p => 
        p.statement.toLowerCase().includes(searchTerm.toLowerCase()) ||
        p.tags.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (selectedTopic !== 'all') {
      result = result.filter(p => p.topic === selectedTopic);
    }

    if (selectedLevel !== 'all') {
      result = result.filter(p => p.level === parseInt(selectedLevel));
    }

    setFilteredProblems(result);
  }, [problems, searchTerm, selectedTopic, selectedLevel]);

  const handleAddProblem = (e) => {
    e.preventDefault();

    const raw = formData.rawLatex;
    if (!raw) {
      alert('Vui lòng dán nội dung bài tập LaTeX vào');
      return;
    }

    let cleanText = raw.replace(/\\begin\{bt\}/g, '').replace(/\\end\{bt\}/g, '').trim();
    let statement = cleanText;
    let solution = '';

    const loigiaiMatch = cleanText.match(/\\loigiai\{([\s\S]*?)\}(?=\s*$|\\end)/);
    if (loigiaiMatch) {
      solution = loigiaiMatch[1].trim();
      statement = cleanText.replace(loigiaiMatch[0], '').trim();
    }

    const newProblem = {
      id: Date.now(),
      statement: statement,
      solution: solution,
      topic: formData.topic,
      level: parseInt(formData.level),
      type: formData.type,
      tags: formData.tags,
      notes: formData.notes,
      dateAdded: new Date().toLocaleDateString('vi-VN'),
      timesUsed: 0
    };

    const updated = [...problems, newProblem];
    setProblems(updated);
    localStorage.setItem('problems', JSON.stringify(updated));

    setFormData({
      rawLatex: '',
      topic: 'Đạo hàm',
      level: 1,
      type: 'Tự luận',
      tags: '',
      notes: ''
    });
    setShowAddForm(false);
    alert('✓ Thêm bài tập thành công!');
  };

  const handleDeleteProblem = (id) => {
    if (window.confirm('Bạn chắc chắn muốn xóa?')) {
      const updated = problems.filter(p => p.id !== id);
      setProblems(updated);
      localStorage.setItem('problems', JSON.stringify(updated));
    }
  };

  const handleExportPDF = () => {
    if (filteredProblems.length === 0) {
      alert('Không có bài tập để export');
      return;
    }

    let content = '';

    filteredProblems.forEach((p) => {
      content += '\\begin{bt}\n';
      content += p.statement + '\n';
      if (p.solution) {
        content += '\\loigiai{\n' + p.solution + '\n}\n';
      }
      content += '\\end{bt}\n\n';
    });

    const element = document.createElement('a');
    element.setAttribute('href', 'data:text/plain;charset=utf-8,' + encodeURIComponent(content));
    element.setAttribute('download', 'problem_bank_export.tex');
    element.style.display = 'none';
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setIsImporting(true);

    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const content = event.target.result;
        const blocks = content.split(/\\begin\{bt\}/g).slice(1);

        if (blocks.length === 0) {
          alert('Không tìm thấy bài tập nào đúng định dạng \\begin{bt}...\\end{bt} trong file.');
          setIsImporting(false);
          return;
        }

        let newProblems = [];
        let itemsToAnalyze = [];

        blocks.forEach((block, index) => {
          const endMatch = block.indexOf('\\end{bt}');
          if (endMatch !== -1) {
            let cleanText = block.substring(0, endMatch).trim();
            let statement = cleanText;
            let solution = '';

            const loigiaiMatch = cleanText.match(/\\loigiai\{([\s\S]*?)\}(?=\s*$|\\end)/);
            if (loigiaiMatch) {
              solution = loigiaiMatch[1].trim();
              statement = cleanText.replace(loigiaiMatch[0], '').trim();
            }

            newProblems.push({
              _tempId: index,
              id: Date.now() + index,
              statement: statement,
              solution: solution,
              topic: 'Chưa phân loại', 
              level: 1,
              type: 'Tự luận',
              tags: 'import',
              notes: 'Được import từ file',
              dateAdded: new Date().toLocaleDateString('vi-VN'),
              timesUsed: 0
            });

            itemsToAnalyze.push(`ID: ${index}\nĐề bài: ${statement}`);
          }
        });

        // CHỈ GỌI AI KHI CÔNG TẮC BẬT
        if (useAI) {
          alert(`Đã tách được ${newProblems.length} câu. Đang nhờ AI phân loại, Thầy vui lòng chờ chút nhé...`);

          const model = genAI.getGenerativeModel({ model: "gemini-3-flash-preview" }); // Khuyến nghị dùng gemini-pro cho ổn định
          const prompt = `Đóng vai một giáo viên Toán cấp 2. Dưới đây là danh sách các bài toán (được đánh số ID).
Hãy phân loại từng bài toán. Trả về kết quả CHỈ LÀ MỘT MẢNG JSON HỢP LỆ, không kèm theo text nào khác.
Cấu trúc JSON mỗi phần tử phải là: {"id": ID_của_bài, "topic": "Chủ đề (chỉ chọn trong: Đạo hàm, Tích phân, Lượng giác, Số phức, Ma trận, Hình học không gian, Xác suất, Giới hạn, Khác)", "level": Độ khó (số nguyên 1, 2, hoặc 3), "type": "Loại (chỉ chọn: Tự luận, Trắc nghiệp, Chứng minh)", "tags": "2-3 từ khóa ngắn gọn cách nhau bằng dấu phẩy"}

Danh sách bài toán:
${itemsToAnalyze.join('\n\n')}
`;

          const result = await model.generateContent(prompt);
          const responseText = result.response.text();

          try {
            const jsonString = responseText.replace(/```json/g, '').replace(/```/g, '').trim();
            const aiClassifications = JSON.parse(jsonString);

            aiClassifications.forEach(aiData => {
              const probIndex = newProblems.findIndex(p => p._tempId === aiData.id);
              if (probIndex !== -1) {
                newProblems[probIndex].topic = aiData.topic || 'Chưa phân loại';
                newProblems[probIndex].level = aiData.level || 1;
                newProblems[probIndex].type = aiData.type || 'Tự luận';
                newProblems[probIndex].tags = aiData.tags || 'import';
              }
            });
          } catch (e) {
            console.error("Lỗi khi parse AI JSON. Lưu bằng giá trị mặc định.", e, responseText);
            alert("AI phản hồi không chuẩn JSON, các bài sẽ được lưu với phân loại mặc định.");
          }
        }

        newProblems = newProblems.map(p => {
          delete p._tempId;
          return p;
        });

        const updated = [...problems, ...newProblems];
        setProblems(updated);
        localStorage.setItem('problems', JSON.stringify(updated));

        if (useAI) {
          alert(`✓ Đã phân loại bằng AI và nhập thành công ${newProblems.length} bài tập!`);
        } else {
          alert(`✓ Đã nhập thành công ${newProblems.length} bài tập (Chưa phân loại)!`);
        }

      } catch (err) {
        console.error("Lỗi trong quá trình import:", err);
        alert("Có lỗi xảy ra trong quá trình đọc file hoặc gọi AI.");
      } finally {
        setIsImporting(false); 
      }
    };

    reader.readAsText(file);
    e.target.value = null;
  };

  // AI OCR: Quét ảnh/PDF sang LaTeX
  const handleOCRUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setIsOCRing(true);
    try {
      // 1. Chuyển đổi file sang định dạng base64 để gửi cho Gemini
      const base64EncodedDataPromise = new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result.split(',')[1]);
        reader.readAsDataURL(file);
      });
      const base64Data = await base64EncodedDataPromise;

      const filePart = {
        inlineData: {
          data: base64Data,
          mimeType: file.type // Hỗ trợ cả image/png, image/jpeg, application/pdf
        }
      };

      // 2. Gọi model hỗ trợ đọc hình ảnh (gemini-1.5-flash)
      const model = genAI.getGenerativeModel({ model: "gemini-3-flash-preview" });

      const prompt = `Trích xuất toàn bộ nội dung câu hỏi toán học trong tài liệu đính kèm sang mã LaTeX.
TUÂN THỦ NGHIÊM NGẶT CÁC QUY TẮC ĐỊNH DẠNG SAU:
1. Bao bọc toàn bộ câu hỏi trong \\begin{bt} và \\end{bt}.
2. Nếu trong ảnh có sẵn lời giải, hãy đặt nội dung đó trong \\loigiai{ ... } và để ngay trước \\end{bt}.
3. TUYỆT ĐỐI dùng \\dfrac thay cho \\frac trong mọi trường hợp.
4. KHÔNG SỬ DỤNG môi trường align, align*, hay equation. Nếu cần xuống dòng chứa công thức, chỉ sử dụng dấu xuống dòng thông thường.
5. Nhận diện loại câu hỏi trong ảnh và trình bày ĐÚNG THEO 1 TRONG CÁC FORM SAU:

   - Form tự luận
     \\begin{bt}
     Nội dung câu hỏi
     \\loigiai{Lời giải nếu có}
     \\end{bt}

   - Form Trắc nghiệm 4 lựa chọn (A, B, C, D):
     \\begin{bt}
     Nội dung câu hỏi
     \\choice
     {Nội dung phương án A}
     {Nội dung phương án B}
     {Nội dung phương án C}
     {Nội dung phương án D}
     \\loigiai{Lời giải nếu có}
     \\end{bt}

   - Form Trắc nghiệm đúng sai (gồm 4 ý a, b, c, d):
     \\begin{bt}
     Nội dung câu hỏi
     \\choiceTF
     {Nội dung ý a}
     {Nội dung ý b}
     {Nội dung ý c}
     {Nội dung ý d}
     \\loigiai{Lời giải nếu có}
     \\end{bt}

   - Form Trắc nghiệm trả lời ngắn (chỉ điền đáp số) hoặc Tự luận:
     \\begin{bt}
     Nội dung câu hỏi
     \\shortans{Đáp số nếu có}
     \\loigiai{Lời giải nếu có}
     \\end{bt}

Trả về kết quả CHỈ LÀ MÃ LATEX ĐÃ ĐƯỢC LÀM SẠCH, tuyệt đối không bọc trong markdown (như \`\`\`latex) và không kèm theo văn bản giải thích nào khác.`;

      alert("Đang phân tích hình ảnh/PDF, Thầy đợi vài giây nhé...");
      const result = await model.generateContent([prompt, filePart]);
      const responseText = result.response.text();

      // 3. Làm sạch mã trả về
      const cleanLatex = responseText.replace(/```latex/g, '').replace(/```/g, '').trim();

      // 4. Mở form và đổ dữ liệu vào
      setShowAddForm(true);
      setFormData({
        ...formData,
        rawLatex: cleanLatex
      });

    } catch (err) {
      console.error("Lỗi OCR:", err);
      alert("Có lỗi khi nhận dạng tài liệu. Thầy thử lại nhé.");
    } finally {
      setIsOCRing(false);
    }

    e.target.value = null; // Reset input
  };

  return (
    <div className="App">
      <header className="header">
        <div className="header-content">
          <h1>🎓 Problem Bank Management</h1>
          <p>Quản lý ngân hàng bài tập Toán chuyên</p>
        </div>
      </header>

      <main className="main-content">
        <div className="container">

          <div className="action-bar">
            <button 
              className="btn btn-primary"
              onClick={() => setShowAddForm(!showAddForm)}
            >
              <Plus size={20} /> {showAddForm ? 'Hủy' : 'Thêm Bài Tập'}
            </button>

            <label className="btn btn-secondary" style={{ cursor: isImporting ? 'not-allowed' : 'pointer', opacity: isImporting ? 0.7 : 1 }}>
              <input 
                type="file" 
                accept=".tex,.txt" 
                style={{ display: 'none' }} 
                onChange={handleFileUpload} 
                disabled={isImporting}
              />
              <Upload size={20} /> {isImporting ? 'Đang xử lý...' : 'Import File'}
            </label>

            {/* Nút OCR quét ảnh */}
            <label className="btn btn-secondary" style={{ cursor: isOCRing ? 'not-allowed' : 'pointer', opacity: isOCRing ? 0.7 : 1, backgroundColor: '#f6ad55' }}>
              <input 
                type="file" 
                accept="image/png, image/jpeg, application/pdf" 
                style={{ display: 'none' }} 
                onChange={handleOCRUpload} 
                disabled={isOCRing}
              />
              <ImageIcon size={20} /> {isOCRing ? 'Đang đọc chữ...' : 'Quét Ảnh/PDF'}
            </label>

            {/* CÔNG TẮC AI Ở ĐÂY */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', backgroundColor: '#e2e8f0', padding: '0 1rem', borderRadius: '8px' }}>
              <input 
                type="checkbox" 
                id="useAI" 
                checked={useAI} 
                onChange={(e) => setUseAI(e.target.checked)}
                disabled={isImporting}
                style={{ width: '18px', height: '18px', cursor: 'pointer' }}
              />
              <label htmlFor="useAI" style={{ cursor: 'pointer', margin: 0, fontWeight: 600, color: '#4a5568' }}>
                Dùng AI
              </label>
            </div>

            <button className="btn btn-secondary" onClick={handleExportPDF}>
              <Download size={20} /> Export ({filteredProblems.length})
            </button>
          </div>

          {showAddForm && (
            <div className="form-container">
              <h2>Thêm Bài Tập Mới</h2>
              <form onSubmit={handleAddProblem}>
                <div className="form-group">
                  <label>Nhập nguyên cụm LaTeX (\begin&#123;bt&#125; ... \end&#123;bt&#125;)</label>
                  <textarea
                    value={formData.rawLatex}
                    onChange={(e) => setFormData({...formData, rawLatex: e.target.value})}
                    placeholder="\begin{bt}&#10;Nội dung đề bài...&#10;\loigiai{ Lời giải... }&#10;\end{bt}"
                    rows="8"
                  />
                </div>

                <div className="form-row">
                  <div className="form-group">
                    <label>Topic</label>
                    <select
                      value={formData.topic}
                      onChange={(e) => setFormData({...formData, topic: e.target.value})}
                    >
                      {topics.map(t => (
                        <option key={t} value={t}>{t}</option>
                      ))}
                    </select>
                  </div>

                  <div className="form-group">
                    <label>Level</label>
                    <select
                      value={formData.level}
                      onChange={(e) => setFormData({...formData, level: e.target.value})}
                    >
                      <option value="1">1 - Cơ bản</option>
                      <option value="2">2 - Trung bình</option>
                      <option value="3">3 - Nâng cao</option>
                    </select>
                  </div>

                  <div className="form-group">
                    <label>Type</label>
                    <select
                      value={formData.type}
                      onChange={(e) => setFormData({...formData, type: e.target.value})}
                    >
                      <option value="Tự luận">Tự luận</option>
                      <option value="Trắc nghiệp">Trắc nghiệp</option>
                      <option value="Chứng minh">Chứng minh</option>
                    </select>
                  </div>
                </div>

                <div className="form-group">
                  <label>Tags (cách nhau bởi dấu phẩy)</label>
                  <input
                    type="text"
                    value={formData.tags}
                    onChange={(e) => setFormData({...formData, tags: e.target.value})}
                    placeholder="đạo hàm, cực trị, tối ưu hóa"
                  />
                </div>

                <div className="form-group">
                  <label>Notes</label>
                  <textarea
                    value={formData.notes}
                    onChange={(e) => setFormData({...formData, notes: e.target.value})}
                    placeholder="Ghi chú cá nhân..."
                    rows="2"
                  />
                </div>

                <button type="submit" className="btn btn-success">Lưu Bài Tập</button>
              </form>
            </div>
          )}

          <div className="filter-bar">
            <div className="search-box">
              <Search size={20} />
              <input
                type="text"
                placeholder="Tìm kiếm bài tập..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="filter-selects">
              <select 
                value={selectedTopic} 
                onChange={(e) => setSelectedTopic(e.target.value)}
              >
                <option value="all">Tất cả chủ đề</option>
                {topics.map(t => (
                  <option key={t} value={t}>{t}</option>
                ))}
              </select>

              <select 
                value={selectedLevel} 
                onChange={(e) => setSelectedLevel(e.target.value)}
              >
                <option value="all">Tất cả cấp độ</option>
                <option value="1">Level 1 - Cơ bản</option>
                <option value="2">Level 2 - Trung bình</option>
                <option value="3">Level 3 - Nâng cao</option>
              </select>
            </div>
          </div>

          <div className="results-section">
            <h2>Kết quả tìm kiếm ({filteredProblems.length})</h2>

            {filteredProblems.length === 0 ? (
              <div className="empty-state">
                <p>📭 Không tìm thấy bài tập nào</p>
                <small>Hãy thêm bài tập đầu tiên!</small>
              </div>
            ) : (
              <div className="problems-list">
                {filteredProblems.map((problem) => (
                  <div key={problem.id} className="problem-card">
                    <div className="problem-header">
                      <h3>{problem.statement.substring(0, 60)}...</h3>
                      <span className={`level level-${problem.level}`}>
                        Level {problem.level}
                      </span>
                    </div>

                    <div className="problem-meta">
                      <span className="topic-badge">{problem.topic}</span>
                      <span className="type-badge">{problem.type}</span>
                      <span className="date">{problem.dateAdded}</span>
                    </div>

                    {problem.tags && (
                      <div className="problem-tags">
                        {problem.tags.split(',').map((tag, idx) => (
                          <span key={idx} className="tag">#{tag.trim()}</span>
                        ))}
                      </div>
                    )}

                    <div className="problem-actions">
                      <button 
                        className="btn btn-sm" 
                        title="Xem chi tiết"
                        onClick={() => setExpandedId(expandedId === problem.id ? null : problem.id)}
                      >
                        👁️ {expandedId === problem.id ? 'Thu gọn' : 'Xem'}
                      </button>

                      <button 
                        className="btn btn-sm btn-danger"
                        onClick={() => handleDeleteProblem(problem.id)}
                      >
                        <Trash2 size={16} /> Xóa
                      </button>
                    </div>

                    {expandedId === problem.id && (
                      <div style={{ marginTop: '1rem', padding: '1rem', backgroundColor: '#f8fafc', borderRadius: '8px', whiteSpace: 'pre-wrap', fontFamily: 'monospace', fontSize: '14px', border: '1px solid #e2e8f0' }}>
                        <strong style={{ color: '#667eea' }}>Đề bài:</strong>
                        <div style={{ marginTop: '0.5rem', marginBottom: '1rem', color: '#333' }}>
                          {problem.statement}
                        </div>

                        {problem.solution && (
                          <>
                            <strong style={{ color: '#48bb78' }}>Lời giải:</strong>
                            <div style={{ marginTop: '0.5rem', color: '#333' }}>
                              {problem.solution}
                            </div>
                          </>
                        )}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="footer">
        <p>Problem Bank v1.0 © 2026 | Powered by React + SQLite</p>
      </footer>
    </div>
  );
}

export default App;
